import React from 'react';
import { Link } from 'react-router-dom';


const hapticVibrate = ()=> navigator.vibrate(20);


 export default class Navigation extends React.Component {

        render(){
            return (  
                 
        <div> 
            <ul className="nav justify-content-center bangers">
                <Link onClick={hapticVibrate} className="nav-link" to="/"><li>Home</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Artwork/Vector"><li>Artwork</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Animation"><li>Animation</li></Link>
                <Link onClick={hapticVibrate} className="nav-link" to="/Projects/Games"><li>Projects</li></Link>
            </ul>
        </div> 
                 
            )
          
        }
       
}
   

