import React from 'react';
import {INSTRUMENT_RACK} from '../static/daw/main/main.js';
import samplerSVG from '../static/daw/assets/sampler.js';


export default class Tools extends React.Component{

    render(){
        
        return(
                <div className="game-container">   
                    <div id="instrument-rack" contentEditable="false" dangerouslySetInnerHTML={{__html: samplerSVG}}></div>
                </div>
        )
    }
    componentDidMount(){
        INSTRUMENT_RACK.Defaults.init();
    }
}
